import {
  ChangeDetectionStrategy,
  Component,
  ViewEncapsulation,
  input,
  output,
} from '@angular/core';

/**
 * A smart component that demonstrates Compodoc JSDoc integration with Storybook.
 */
@Component({
  selector: 'smart-ngx-smart-components',
  imports: [],
  template: `<p>NgxSmartComponents works!</p>`,
  styles: `
    :host {
      display: block;
    }
  `,
  encapsulation: ViewEncapsulation.Emulated,
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class NgxSmartComponents {
  /** The label text displayed by the component. */
  readonly label = input<string>('');

  /** Emitted when the component value changes. */
  readonly changed = output<string>();
}

